case "config-patch": {
  const result = await deployConfigPatch(action, dryRun, verbose, home, planned);
  if (result.error === null) succeeded++;
  else failed.push({ action, error: result.error });
  break;
}
```

Pass `planned` array by reference into the helpers so they can push into it.

