  kind: "skill-dir",
  skill: action.skill,
  agent: action.agent,
  source: action.source,
  target: action.target,
  method: action.method,
});
```

Add `planned: PlannedChange[]` as a parameter to `deploySkillDir`.

#### 4f. Update `executeDeploy` return value

Return `{ succeeded, failed, planned }` at the end.

