import { lstat, readFile, rm, unlink, writeFile } from "node:fs/promises";
import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
import { logger } from "../logger.ts";
import type {
  AgentId,
  Manifest,
  PlannedChange,
  RevertAction,
} from "../types.ts";
import type { ConfigPatchRegistryEntry } from "../schemas/registry.ts";
import { lookupDeployment, unregisterDeployment } from "./ownership.ts";
import { resolveAgentSkillPath } from "./resolve.ts";

export function planRevert(
  manifest: Manifest,
  detectedAgents: AgentId[],
  home: string,
): RevertAction[] {
  const actions: RevertAction[] = [];

  for (const skill of manifest.skills) {
    for (const agentId of skill.agents) {
      if (!detectedAgents.includes(agentId)) continue;

      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        target,
      });
    }
  }

  return actions;
}

export function planRevertAll(
  manifest: Manifest,
  home: string,
): RevertAction[] {
  const actions: RevertAction[] = [];

  for (const skill of manifest.skills) {
    for (const agentId of skill.agents) {
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        target,
      });
    }
  }

  return actions;
}

type RevertOutcome =
  | { outcome: "ok" }
  | { outcome: "skip" }
  | { outcome: "fail"; error: string };

function lstatOutcome(
  err: unknown,
): { outcome: "skip" } | { outcome: "fail"; error: string } {
  if ((err as NodeJS.ErrnoException).code === "ENOENT") {
    return { outcome: "skip" };
  }
  const msg = err instanceof Error ? err.message : String(err);
  return { outcome: "fail", error: msg };
}

export async function executeRevert(
  actions: RevertAction[],
  dryRun: boolean,
  verbose: boolean,
  home: string,
): Promise<{
  succeeded: number;
  skipped: number;
  failed: Array<{ action: RevertAction; error: string }>;
  planned: PlannedChange[];
}> {
  let succeeded = 0;
  let skipped = 0;
  const failed: Array<{ action: RevertAction; error: string }> = [];
  const planned: PlannedChange[] = [];

  for (const action of actions) {
    switch (action.kind) {
      case "skill-dir": {
        const result = await executeRevertAction(
          action,
          dryRun,
          verbose,
          home,
          planned,
        );
        if (result.outcome === "fail") {
          failed.push({ action, error: result.error });
        } else if (result.outcome === "skip") {
          skipped++;
        } else {
          succeeded++;
        }
        break;
      }
      case "file-write": {
        const result = await revertFileWrite(
          action,
          dryRun,
          verbose,
          home,
          planned,
        );
        if (result.outcome === "fail") {
          failed.push({ action, error: result.error });
        } else if (result.outcome === "skip") {
          skipped++;
        } else {
          succeeded++;
        }
        break;
