        testManifest,
        sourceDir,
        ["claude-code"],
        "/home/test",
      );
      assert.equal(actions.length, 1);
      assert.equal(actions[0]?.agent, "claude-code");
      assert.equal(actions[0]?.skill, "test-skill");
    } finally {
      rmSync(sourceDir, { recursive: true });
    }
  });

