    const home = makeTmpDir();
    try {
      await registerDeployment(home, "/target/a", {
        kind: "skill-dir",
        source: "/src/a",
        skill: "a",
        agent: "claude-code",
        method: "symlink",
      });
      // Should not throw
      await unregisterDeployment(home, "/target/nonexistent");

      const entry = await lookupDeployment(home, "/target/a");
      assert.ok(entry);
    } finally {
      rmSync(home, { recursive: true });
    }
  });
});

