    patch,
  });
  return { error: null };
}

try {
  // Guard against double-patching by a different skill/agent
  const existingEntry = await lookupDeployment(home, action.target);
  if (
    existingEntry &&
    (existingEntry.skill !== action.skill ||
      existingEntry.agent !== action.agent)
  ) {
    throw new Error(
      `Config "${action.target}" is already patched by skill "${existingEntry.skill}" for agent "${existingEntry.agent}" — refusing to double-patch`,
    );
  }

  // Read and parse the target config file
  let rawContent: string;
  try {
    rawContent = await readFile(action.target, "utf-8");
  } catch (err) {
    const code = (err as NodeJS.ErrnoException).code;
    if (code === "ENOENT") {
      throw new Error(`Config file not found: ${action.target}`);
    }
    throw err;
  }

  let original: Record<string, unknown>;
  try {
    const parsed: unknown = JSON.parse(rawContent);
    if (!isPlainObject(parsed)) {
      throw new Error(`Config file is not a JSON object: ${action.target}`);
    }
    original = parsed;
  } catch (err) {
    if (err instanceof Error && err.message.startsWith("Config file"))
      throw err;
    throw new Error(`Config file is not valid JSON: ${action.target}`);
  }

  // Compute undo patch (original values for patched keys; null = key was absent)
  const undoPatch: Record<string, unknown> = {};
  for (const key of Object.keys(patch)) {
    undoPatch[key] = key in original ? original[key] : null;
  }

  // Apply JSON Merge Patch (RFC 7396)
  const patched: Record<string, unknown> = { ...original };
  for (const [key, value] of Object.entries(patch)) {
    if (value === null) {
      delete patched[key];
    } else {
      patched[key] = value;
    }
  }

  await writeFile(
    action.target,
    `${JSON.stringify(patched, null, 2)}\n`,
    "utf-8",
  );
  await registerDeployment(home, action.target, {
    kind: "config-patch",
    patch,
    undoPatch,
    skill: action.skill,
    agent: action.agent,
  });

