import { lstat, readFile, rm, unlink, writeFile } from "node:fs/promises";
import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
import { logger } from "../logger.ts";
import type {
  AgentId,
  Manifest,
  PlannedChange,
  RevertAction,
} from "../types.ts";
import type { ConfigPatchRegistryEntry } from "../schemas/registry.ts";
import { lookupDeployment, unregisterDeployment } from "./ownership.ts";
import { resolveAgentSkillPath } from "./resolve.ts";

export function planRevert(
  manifest: Manifest,
  detectedAgents: AgentId[],
  home: string,
): RevertAction[] {
  const actions: RevertAction[] = [];

  for (const skill of manifest.skills) {
    for (const agentId of skill.agents) {
      if (!detectedAgents.includes(agentId)) continue;

      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        target,
      });
    }
  }

  return actions;
}

export function planRevertAll(
  manifest: Manifest,
  home: string,
): RevertAction[] {
  const actions: RevertAction[] = [];

  for (const skill of manifest.skills) {
    for (const agentId of skill.agents) {
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        target,
      });
    }
  }

  return actions;
}

type RevertOutcome =
  | { outcome: "ok" }
  | { outcome: "skip" }
  | { outcome: "fail"; error: string };

function lstatOutcome(
  err: unknown,
): { outcome: "skip" } | { outcome: "fail"; error: string } {
  if ((err as NodeJS.ErrnoException).code === "ENOENT") {
    return { outcome: "skip" };
  }
  const msg = err instanceof Error ? err.message : String(err);
  return { outcome: "fail", error: msg };
}

export async function executeRevert(
  actions: RevertAction[],
  dryRun: boolean,
  verbose: boolean,
  home: string,
): Promise<{
  succeeded: number;
  skipped: number;
  failed: Array<{ action: RevertAction; error: string }>;
  planned: PlannedChange[];
}> {
  let succeeded = 0;
  let skipped = 0;
  const failed: Array<{ action: RevertAction; error: string }> = [];
  const planned: PlannedChange[] = [];

  for (const action of actions) {
    switch (action.kind) {
      case "skill-dir": {
        const result = await executeRevertAction(
          action,
          dryRun,
          verbose,
          home,
          planned,
        );
        if (result.outcome === "fail") {
          failed.push({ action, error: result.error });
        } else if (result.outcome === "skip") {
          skipped++;
        } else {
          succeeded++;
        }
        break;
      }
      case "file-write": {
        const result = await revertFileWrite(
          action,
          dryRun,
          verbose,
          home,
          planned,
        );
        if (result.outcome === "fail") {
          failed.push({ action, error: result.error });
        } else if (result.outcome === "skip") {
          skipped++;
        } else {
          succeeded++;
        }
        break;
      }
      case "config-patch": {
        const result = await revertConfigPatch(
          action,
          dryRun,
          verbose,
          home,
          planned,
        );
        if (result.outcome === "fail") {
          failed.push({ action, error: result.error });
        } else if (result.outcome === "skip") {
          skipped++;
        } else {
          succeeded++;
        }
        break;
      }
      default: {
        throw new Error(`Unhandled revert action kind: ${action}`);
      }
    }
  }

  return { succeeded, skipped, failed, planned };
}

async function executeRevertAction(
  action: RevertAction,
  dryRun: boolean,
  verbose: boolean,
  home: string,
  planned: PlannedChange[],
): Promise<RevertOutcome> {
  const label = `${action.skill} -> ${action.agent}`;

  let stat: Awaited<ReturnType<typeof lstat>>;
  try {
    stat = await lstat(action.target);
  } catch (err) {
    const result = lstatOutcome(err);
    if (result.outcome === "skip") {
      logger.skip(label, "(not found, skipping)");
      return result;
    }
    logger.fail(label, result.error);
    return result;
  }

  const entry = await lookupDeployment(home, action.target);
  if (!entry || entry.skill !== action.skill || entry.agent !== action.agent) {
    logger.warn(
      label,
      `skipping: ${action.target} is not in the deployment registry — not managed by inception-engine`,
    );
    return { outcome: "skip" };
  }

  if (dryRun) {
    logger.plan(label);
    logger.detail(`would remove: ${action.target}`);
    planned.push({
      verb: "remove",
      kind: "skill-dir",
      skill: action.skill,
      agent: action.agent,
      target: action.target,
    });
    return { outcome: "ok" };
  }

  try {
    if (stat.isSymbolicLink()) {
      await unlink(action.target);
    } else {
      await rm(action.target, { recursive: true });
    }
    await unregisterDeployment(home, action.target);
    logger.ok(label);
    if (verbose) {
      logger.detail(`removed: ${action.target}`);
    }
    return { outcome: "ok" };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    logger.fail(label, msg);
    return { outcome: "fail", error: msg };
  }
}

async function revertFileWrite(
  action: RevertAction,
  dryRun: boolean,
  verbose: boolean,
  home: string,
  planned: PlannedChange[],
): Promise<RevertOutcome> {
  const label = `${action.skill} -> ${action.agent}`;

  try {
    await lstat(action.target);
  } catch (err) {
    const result = lstatOutcome(err);
    if (result.outcome === "skip") {
      logger.skip(label, "(not found, skipping)");
      return result;
    }
    logger.fail(label, result.error);
    return result;
  }

  const entry = await lookupDeployment(home, action.target);
  if (!entry || entry.skill !== action.skill || entry.agent !== action.agent) {
    logger.warn(
      label,
      `skipping: ${action.target} is not in the deployment registry — not managed by inception-engine`,
    );
    return { outcome: "skip" };
  }

  if (dryRun) {
    logger.plan(label);
    logger.detail(`would remove: ${action.target}`);
    planned.push({
      verb: "remove",
      kind: "file-write",
      skill: action.skill,
      agent: action.agent,
      target: action.target,
    });
    return { outcome: "ok" };
  }

  try {
    await unlink(action.target);
    await unregisterDeployment(home, action.target);
    logger.ok(label);
    if (verbose) {
      logger.detail(`removed: ${action.target}`);
    }
    return { outcome: "ok" };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    logger.fail(label, msg);
    return { outcome: "fail", error: msg };
  }
}

async function revertConfigPatch(
  action: RevertAction,
  dryRun: boolean,
  verbose: boolean,
  home: string,
  planned: PlannedChange[],
): Promise<RevertOutcome> {
  const label = `${action.skill} -> ${action.agent}`;

  try {
    await lstat(action.target);
  } catch (err) {
    const result = lstatOutcome(err);
    if (result.outcome === "skip") {
      logger.skip(label, "(not found, skipping)");
      return result;
    }
    logger.fail(label, result.error);
    return result;
  }

  const entry = await lookupDeployment(home, action.target);
  if (
    !entry ||
    entry.kind !== "config-patch" ||
    entry.skill !== action.skill ||
    entry.agent !== action.agent
  ) {
    logger.warn(
      label,
      `skipping: ${action.target} is not in the deployment registry — not managed by inception-engine`,
    );
    return { outcome: "skip" };
  }

  const configPatchEntry = entry as ConfigPatchRegistryEntry;

  if (dryRun) {
    logger.plan(label);
    logger.detail(
      `would unapply patch: ${JSON.stringify(configPatchEntry.undoPatch)} -> ${action.target}`,
    );
    planned.push({
      verb: "unapply-patch",
      kind: "config-patch",
      skill: action.skill,
      agent: action.agent,
      target: action.target,
      patch: configPatchEntry.undoPatch,
    });
    return { outcome: "ok" };
  }

  try {
    const rawContent = await readFile(action.target, "utf-8");
    let current: Record<string, unknown>;
    try {
      const parsed: unknown = JSON.parse(rawContent);
      if (
        typeof parsed !== "object" ||
        parsed === null ||
        Array.isArray(parsed)
      ) {
        throw new Error(`Config file is not a JSON object: ${action.target}`);
      }
      current = parsed as Record<string, unknown>;
    } catch (err) {
      if (err instanceof Error && err.message.startsWith("Config file"))
        throw err;
      throw new Error(`Config file is not valid JSON: ${action.target}`);
    }

    // Apply undo patch: restore original values, delete keys that were newly added
    const restored: Record<string, unknown> = { ...current };
    for (const [key, originalValue] of Object.entries(
      configPatchEntry.undoPatch,
    )) {
      if (originalValue === null) {
        delete restored[key];
      } else {
        restored[key] = originalValue;
      }
    }

    await writeFile(
      action.target,
      `${JSON.stringify(restored, null, 2)}\n`,
      "utf-8",
    );
    await unregisterDeployment(home, action.target);
    logger.ok(label);
    if (verbose) {
      logger.detail(`unapplied patch from: ${action.target}`);
    }
    return { outcome: "ok" };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    logger.fail(label, msg);
    return { outcome: "fail", error: msg };
  }
}

