async function revertConfigPatch(
  action: RevertAction,
  dryRun: boolean,
  verbose: boolean,
  home: string,
  planned: PlannedChange[],
): Promise<RevertOutcome> {
  const label = `${action.skill} -> ${action.agent}`;

  try {
    await lstat(action.target);
  } catch (err) {
    const result = lstatOutcome(err);
    if (result.outcome === "skip") {
      logger.skip(label, "(not found, skipping)");
      return result;
    }
    logger.fail(label, result.error);
    return result;
  }

  const entry = await lookupDeployment(home, action.target);
  if (
    !entry ||
    entry.kind !== "config-patch" ||
    entry.skill !== action.skill ||
    entry.agent !== action.agent
  ) {
    logger.warn(
      label,
      `skipping: ${action.target} is not in the deployment registry — not managed by inception-engine`,
    );
    return { outcome: "skip" };
  }

  const configPatchEntry = entry as ConfigPatchRegistryEntry;

  if (dryRun) {
    logger.plan(label);
    logger.detail(
      `would unapply patch: ${JSON.stringify(configPatchEntry.undoPatch)} -> ${action.target}`,
    );
    planned.push({
      verb: "unapply-patch",
      kind: "config-patch",
      skill: action.skill,
      agent: action.agent,
      target: action.target,
      patch: configPatchEntry.undoPatch,
    });
    return { outcome: "ok" };
  }

  try {
    const rawContent = await readFile(action.target, "utf-8");
    let current: Record<string, unknown>;
    try {
      const parsed: unknown = JSON.parse(rawContent);
      if (
        typeof parsed !== "object" ||
        parsed === null ||
        Array.isArray(parsed)
      ) {
        throw new Error(`Config file is not a JSON object: ${action.target}`);
      }
      current = parsed as Record<string, unknown>;
    } catch (err) {
      if (err instanceof Error && err.message.startsWith("Config file"))
        throw err;
      throw new Error(`Config file is not valid JSON: ${action.target}`);
    }

    // Apply undo patch: restore original values, delete keys that were newly added
    const restored: Record<string, unknown> = { ...current };
    for (const [key, originalValue] of Object.entries(
      configPatchEntry.undoPatch,
    )) {
      if (originalValue === null) {
        delete restored[key];
      } else {
        restored[key] = originalValue;
      }
    }

    await writeFile(
      action.target,
      `${JSON.stringify(restored, null, 2)}\n`,
      "utf-8",
    );
    await unregisterDeployment(home, action.target);
    logger.ok(label);
    if (verbose) {
      logger.detail(`unapplied patch from: ${action.target}`);
    }
    return { outcome: "ok" };
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    logger.fail(label, msg);
    return { outcome: "fail", error: msg };
  }
}

